    sem_t *p = sem_open("/kf_ex_pool", O_CREAT|O_EXCL, 0644, 1);
    int v;
    sem_getvalue(p, &v); printf("Pool: %d\n", v);
    sem_wait(p);
    sem_getvalue(p, &v); printf("Acquired: %d\n", v);
    sem_post(p);
    sem_getvalue(p, &v); printf("Released: %d\n", v);
    sem_close(p); sem_unlink("/kf_ex_pool");
}
